import React, { createContext, useState, useEffect } from 'react';

export const LocationContext = createContext();

export const LocationProvider = ({ children }) => {
  const [selectedLocation, setSelectedLocation] = useState(null);

  // Загружаем сохраненную локацию при монтировании компонента
  useEffect(() => {
    const savedLocation = localStorage.getItem('selectedLocation');
    if (savedLocation) {
      try {
        setSelectedLocation(JSON.parse(savedLocation));
      } catch (error) {
        console.error('Error parsing saved location:', error);
        localStorage.removeItem('selectedLocation');
      }
    }
  }, []);

  // Функция для установки выбранной локации с сохранением в localStorage
  const saveSelectedLocation = (location) => {
    setSelectedLocation(location);
    if (location) {
      localStorage.setItem('selectedLocation', JSON.stringify(location));
    } else {
      localStorage.removeItem('selectedLocation');
    }
  };

  return (
    <LocationContext.Provider value={{ 
      selectedLocation, 
      setSelectedLocation: saveSelectedLocation 
    }}>
      {children}
    </LocationContext.Provider>
  );
};

export default LocationProvider;
